module RefModule(
    input clk,
    input parallel_load,
    input [3:0] in,
    output reg out
);reg [3:0] shift_reg;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (parallel_load) begin
        shift_reg <= in;
    end else begin
        shift_reg <= {shift_reg[2:0], shift_reg[3]};
    end
end

assign out = shift_reg[0];

endmodule
